/**
 * Format cents as a USD currency string.
 * formatCurrency(1999) => "$19.99"
 */
export function formatCurrency(cents: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(cents / 100);
}

